import sys

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    A = list(map(int, input[1:]))

    first_max = second_max = -1

    for num in A:
        if num > first_max:
            second_max = first_max
            first_max = num
        elif num > second_max and num != first_max:
            second_max = num

    print(second_max)

if __name__ == "__main__":
    main()
